"use client";

import * as React from "react";
import { createPortal } from "react-dom";
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
  CommandShortcut
} from "./command";

export type CommandMenuItem = {
  description?: string;
  group?: string;
  id: string;
  keywords?: string[];
  shortcut?: string;
  title: string;
};

export type CommandMenuProps = {
  emptyText?: string;
  items: readonly CommandMenuItem[];
  onOpenChange: (open: boolean) => void;
  onSelect: (item: CommandMenuItem) => void;
  open: boolean;
  placeholder?: string;
  title?: string;
};

export function CommandMenu({
  emptyText = "No results found.",
  items,
  onOpenChange,
  onSelect,
  open,
  placeholder = "Search commands...",
  title = "Command menu"
}: CommandMenuProps) {
  const inputRef = React.useRef<HTMLInputElement | null>(null);
  const groupedItems = React.useMemo(() => {
    const groups: Array<{ items: CommandMenuItem[]; label: string }> = [];
    for (const item of items) {
      const label = item.group ?? "Commands";
      const existingGroup = groups.find((group) => group.label === label);
      if (existingGroup) existingGroup.items.push(item);
      else groups.push({ items: [item], label });
    }
    return groups;
  }, [items]);

  React.useEffect(() => {
    if (!open) return undefined;

    const previousOverflow = document.body.style.overflow;
    document.body.style.overflow = "hidden";
    window.setTimeout(() => inputRef.current?.focus(), 0);

    function onKeyDown(event: KeyboardEvent) {
      if (event.key === "Escape") onOpenChange(false);
    }

    window.addEventListener("keydown", onKeyDown);
    return () => {
      document.body.style.overflow = previousOverflow;
      window.removeEventListener("keydown", onKeyDown);
    };
  }, [onOpenChange, open]);

  if (!open || typeof document === "undefined") return null;

  return createPortal(
    <div className="fixed inset-0 z-50 grid place-items-start overflow-hidden bg-[#28231f]/56 p-3 axie-fade sm:p-6">
      <button
        aria-label="Close command menu"
        className="absolute inset-0 cursor-default"
        type="button"
        onClick={() => onOpenChange(false)}
      />
      <section
        aria-label={title}
        aria-modal="true"
        className="relative mx-auto max-h-[min(680px,calc(100dvh-24px))] w-full max-w-[620px] overflow-hidden rounded-[20px] border border-axie-line bg-[#fffdf7] text-axie-ink shadow-[0_30px_90px_color-mix(in_srgb,var(--axie-color-ink)_28%,transparent)] ring-1 ring-white/70 axie-pop sm:max-h-[min(720px,calc(100dvh-48px))]"
        role="dialog"
      >
        <Command className="max-h-[min(680px,calc(100dvh-24px))] grid-rows-[auto_minmax(0,1fr)_auto] sm:max-h-[min(720px,calc(100dvh-48px))]" shouldFilter>
          <div className="grid gap-3 border-b border-axie-line bg-[#fffdf7] px-3 pb-3 pt-3">
            <div className="flex items-center justify-between gap-3 px-1">
              <p className="m-0 text-[12px] font-black leading-none text-axie-muted">{title}</p>
              <kbd className="rounded-[7px] border border-axie-line bg-axie-surface-soft px-1.5 py-1 font-mono text-[11px] font-bold leading-none text-axie-muted">
                Esc
              </kbd>
            </div>
            <CommandInput placeholder={placeholder} ref={inputRef} />
          </div>
          <CommandList>
            <CommandEmpty>
              <div className="h-9 w-9 rounded-[12px] border border-axie-line bg-axie-surface-soft" />
              <p className="m-0 text-[14px] font-black text-axie-ink">{emptyText}</p>
              <p className="m-0 max-w-[34ch] text-[12px] font-bold leading-5 text-axie-muted">
                Try a component name, token, or page title.
              </p>
            </CommandEmpty>
            {groupedItems.map((group) => (
              <CommandGroup heading={group.label} key={group.label}>
                {group.items.map((item) => (
                  <CommandItem
                    key={item.id}
                    keywords={[item.title, item.description ?? "", item.group ?? "", ...(item.keywords ?? [])]}
                    value={item.id}
                    onSelect={() => {
                      onSelect(item);
                      onOpenChange(false);
                    }}
                  >
                    <span className="grid min-w-0 gap-1">
                      <span className="truncate text-[14px] font-black leading-5">{item.title}</span>
                      {item.description ? (
                        <span className="max-h-8 overflow-hidden text-[12px] font-bold leading-4 text-axie-muted">
                          {item.description}
                        </span>
                      ) : null}
                    </span>
                    {item.shortcut ? <CommandShortcut>{item.shortcut}</CommandShortcut> : null}
                  </CommandItem>
                ))}
              </CommandGroup>
            ))}
          </CommandList>
          <div className="hidden items-center justify-between border-t border-axie-line bg-[#eee6d9] px-3 py-2 text-[11px] font-bold text-axie-muted sm:flex">
            <span>Arrow keys to move</span>
            <span>Enter to open</span>
          </div>
        </Command>
      </section>
    </div>,
    document.body
  );
}

"use client";

import * as React from "react";
import { Command as CommandPrimitive } from "cmdk";
import { cn } from "../lib/cn";

export const Command = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive>
>(({ className, ...props }, ref) => (
  <CommandPrimitive
    className={cn("grid min-h-0 bg-[#fffdf7] text-axie-ink", className)}
    ref={ref}
    {...props}
  />
));

Command.displayName = "Command";

export const CommandInput = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.Input>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.Input>
>(({ className, ...props }, ref) => (
  <div className="grid min-h-12 grid-cols-[auto_minmax(0,1fr)] items-center gap-3 rounded-[14px] border border-axie-line bg-[#eee6d9] px-3 shadow-[inset_0_1px_0_color-mix(in_srgb,var(--axie-color-surface)_60%,transparent)] focus-within:border-axie-accent/50 focus-within:ring-2 focus-within:ring-axie-accent/16">
    <span
      aria-hidden
      className="relative h-4 w-4 rounded-full border-2 border-axie-muted/70 after:absolute after:-bottom-1 after:-right-1 after:h-2 after:w-0.5 after:rotate-[-45deg] after:rounded-full after:bg-axie-muted/70"
    />
    <CommandPrimitive.Input
      className={cn(
        "h-11 min-w-0 bg-transparent text-[16px] font-black text-axie-ink outline-none placeholder:text-axie-muted/54 disabled:cursor-not-allowed disabled:opacity-50",
        className
      )}
      ref={ref}
      {...props}
    />
  </div>
));

CommandInput.displayName = "CommandInput";

export const CommandList = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.List>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.List>
>(({ className, ...props }, ref) => (
  <CommandPrimitive.List
    className={cn("min-h-0 overflow-y-auto bg-[#fffdf7] p-2", className)}
    ref={ref}
    {...props}
  />
));

CommandList.displayName = "CommandList";

export const CommandEmpty = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.Empty>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.Empty>
>(({ className, ...props }, ref) => (
  <CommandPrimitive.Empty
    className={cn("grid justify-items-center gap-2 px-3 py-10 text-center", className)}
    ref={ref}
    {...props}
  />
));

CommandEmpty.displayName = "CommandEmpty";

export const CommandGroup = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.Group>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.Group>
>(({ className, ...props }, ref) => (
  <CommandPrimitive.Group
    className={cn(
      "grid gap-1 [&_[cmdk-group-heading]]:px-2 [&_[cmdk-group-heading]]:pt-1 [&_[cmdk-group-heading]]:text-[11px] [&_[cmdk-group-heading]]:font-black [&_[cmdk-group-heading]]:leading-5 [&_[cmdk-group-heading]]:text-axie-muted",
      className
    )}
    ref={ref}
    {...props}
  />
));

CommandGroup.displayName = "CommandGroup";

export const CommandItem = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.Item>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.Item>
>(({ className, ...props }, ref) => (
  <CommandPrimitive.Item
    className={cn(
      "grid min-h-14 cursor-pointer select-none grid-cols-[minmax(0,1fr)_auto] items-center gap-3 rounded-[14px] px-3 py-2 text-left outline-none axie-pressable data-[disabled=true]:pointer-events-none data-[disabled=true]:opacity-50 data-[selected=true]:bg-axie-accent-soft data-[selected=true]:text-axie-ink data-[selected=true]:shadow-[inset_0_1px_0_color-mix(in_srgb,var(--axie-color-surface)_65%,transparent)]",
      className
    )}
    ref={ref}
    {...props}
  />
));

CommandItem.displayName = "CommandItem";

export function CommandShortcut({
  className,
  ...props
}: React.HTMLAttributes<HTMLSpanElement>) {
  return (
    <span
      className={cn(
        "rounded-[7px] border border-axie-line bg-axie-surface px-1.5 py-1 font-mono text-[11px] font-bold leading-none text-axie-muted",
        className
      )}
      {...props}
    />
  );
}

type ClassValue = string | false | null | undefined;

export function cn(...values: ClassValue[]) {
  return values.filter(Boolean).join(" ");
}

@theme inline {
  --color-axie-ink: var(--axie-color-ink);
  --color-axie-paper: var(--axie-color-paper);
  --color-axie-surface: var(--axie-color-surface);
  --color-axie-surface-soft: var(--axie-color-surface-soft);
  --color-axie-muted: var(--axie-color-muted);
  --color-axie-line: var(--axie-color-line);
  --color-axie-accent: var(--axie-color-accent);
  --color-axie-accent-soft: var(--axie-color-accent-soft);
  --color-axie-danger: var(--axie-color-danger);
  --color-axie-danger-soft: var(--axie-color-danger-soft);
  --color-axie-warning: var(--axie-color-warning);
  --color-axie-warning-soft: var(--axie-color-warning-soft);
  --color-axie-info: var(--axie-color-info);
  --color-axie-info-soft: var(--axie-color-info-soft);
  --radius-axie-card: var(--axie-radius-card);
  --radius-axie-control: var(--axie-radius-control);
  --radius-axie-sheet: var(--axie-radius-sheet);
  --radius-axie-pill: var(--axie-radius-pill);
  --spacing-axie-page: var(--axie-space-page);
  --spacing-axie-xs: var(--axie-space-xs);
  --spacing-axie-sm: var(--axie-space-sm);
  --spacing-axie-md: var(--axie-space-md);
  --spacing-axie-lg: var(--axie-space-lg);
  --spacing-axie-xl: var(--axie-space-xl);
  --spacing-axie-2xl: var(--axie-space-2xl);
  --shadow-axie-raised: 0 16px 36px color-mix(in srgb, var(--axie-color-ink) 10%, transparent);
  --shadow-axie-soft: 0 10px 24px color-mix(in srgb, var(--axie-color-ink) 6%, transparent);
  --shadow-axie-nav: 0 16px 38px color-mix(in srgb, var(--axie-color-ink) 12%, transparent);
}

:root {
  --axie-color-ink: #263024;
  --axie-color-paper: #f4f1e6;
  --axie-color-surface: #fffdf4;
  --axie-color-surface-soft: #e8ead6;
  --axie-color-muted: #68705d;
  --axie-color-line: #d7d2b9;
  --axie-color-accent: #6f7f3f;
  --axie-color-accent-soft: #e0e8c7;
  --axie-color-danger: #a45447;
  --axie-color-danger-soft: #efd8d0;
  --axie-color-warning: #947236;
  --axie-color-warning-soft: #ecdcb8;
  --axie-color-info: #4d6972;
  --axie-color-info-soft: #dce8e6;
  --axie-radius-card: 10px;
  --axie-radius-control: 12px;
  --axie-radius-sheet: 30px;
  --axie-radius-pill: 999px;
  --axie-space-page: 20px;
  --axie-space-xs: 6px;
  --axie-space-sm: 10px;
  --axie-space-md: 14px;
  --axie-space-lg: 20px;
  --axie-space-xl: 28px;
  --axie-space-2xl: 36px;
  --axie-motion-fast: 160ms;
  --axie-motion-base: 240ms;
  --axie-motion-slow: 360ms;
  --axie-motion-ease: cubic-bezier(0.2, 0.9, 0.2, 1);
  --axie-motion-spring: cubic-bezier(0.16, 1, 0.3, 1);
  --axie-motion-pop: cubic-bezier(0.18, 1.24, 0.3, 1);
}

.axie-pressable {
  transform: translate3d(0, 0, 0) scale(1);
  transition-duration: var(--axie-motion-base);
  transition-property: background-color, border-color, box-shadow, color, opacity, transform;
  transition-timing-function: var(--axie-motion-spring);
  will-change: transform;
}

.axie-pressable:hover {
  transform: translate3d(0, -1px, 0) scale(1.005);
}

.axie-pressable:active {
  transform: translate3d(0, 0, 0) scale(0.985);
}

.axie-enter {
  animation: axie-enter var(--axie-motion-slow) var(--axie-motion-spring) both;
}

.axie-pop {
  animation: axie-pop var(--axie-motion-slow) var(--axie-motion-pop) both;
}

.axie-fade {
  animation: axie-fade var(--axie-motion-base) ease-out both;
}

.axie-sheet-backdrop {
  animation: axie-fade var(--axie-motion-fast) ease-out both;
}

.axie-sheet-panel {
  animation: axie-sheet-panel-in var(--axie-motion-slow) var(--axie-motion-ease) both;
}

.axie-row-enter {
  animation: axie-row-in var(--axie-motion-base) var(--axie-motion-ease) both;
  animation-delay: var(--axie-row-delay, 0ms);
}

.axie-slider {
  --axie-slider-fill: 0%;
  -webkit-appearance: none;
  appearance: none;
  block-size: 32px;
  inline-size: 100%;
  margin: 0;
  background: transparent;
  color: var(--axie-color-accent);
  cursor: pointer;
}

.axie-slider:disabled {
  cursor: not-allowed;
  opacity: 0.56;
}

.axie-slider::-webkit-slider-runnable-track {
  block-size: 12px;
  border: 1px solid color-mix(in srgb, var(--axie-color-line) 88%, var(--axie-color-ink));
  border-radius: var(--axie-radius-pill);
  background:
    linear-gradient(
      to right,
      var(--axie-color-accent) 0 var(--axie-slider-fill),
      color-mix(in srgb, var(--axie-color-surface-soft) 84%, var(--axie-color-paper)) var(--axie-slider-fill) 100%
    );
  box-shadow: inset 0 1px 0 color-mix(in srgb, var(--axie-color-surface) 74%, transparent);
  transition:
    background var(--axie-motion-base) var(--axie-motion-spring),
    border-color var(--axie-motion-base) var(--axie-motion-spring);
}

.axie-slider::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  block-size: 22px;
  inline-size: 22px;
  margin-block-start: -6px;
  border: 2px solid var(--axie-color-surface);
  border-radius: 50%;
  background:
    radial-gradient(
      circle at 34% 32%,
      color-mix(in srgb, var(--axie-color-accent-soft) 62%, white) 0 22%,
      var(--axie-color-accent) 58%
    );
  box-shadow:
    0 2px 0 color-mix(in srgb, var(--axie-color-ink) 16%, transparent),
    0 10px 20px color-mix(in srgb, var(--axie-color-accent) 22%, transparent);
  transition:
    box-shadow var(--axie-motion-base) var(--axie-motion-spring),
    transform var(--axie-motion-base) var(--axie-motion-spring);
}

.axie-slider:hover::-webkit-slider-thumb {
  transform: scale(1.05);
}

.axie-slider:active::-webkit-slider-thumb {
  transform: scale(0.94);
}

.axie-slider:focus-visible::-webkit-slider-thumb {
  box-shadow:
    0 2px 0 color-mix(in srgb, var(--axie-color-ink) 16%, transparent),
    0 10px 20px color-mix(in srgb, var(--axie-color-accent) 22%, transparent),
    0 0 0 5px color-mix(in srgb, var(--axie-color-accent) 22%, transparent);
}

.axie-slider::-moz-range-track {
  block-size: 12px;
  border: 1px solid color-mix(in srgb, var(--axie-color-line) 88%, var(--axie-color-ink));
  border-radius: var(--axie-radius-pill);
  background: color-mix(in srgb, var(--axie-color-surface-soft) 84%, var(--axie-color-paper));
  box-shadow: inset 0 1px 0 color-mix(in srgb, var(--axie-color-surface) 74%, transparent);
}

.axie-slider::-moz-range-progress {
  block-size: 12px;
  border-radius: var(--axie-radius-pill);
  background: var(--axie-color-accent);
}

.axie-slider::-moz-range-thumb {
  box-sizing: border-box;
  block-size: 22px;
  inline-size: 22px;
  border: 2px solid var(--axie-color-surface);
  border-radius: 50%;
  background:
    radial-gradient(
      circle at 34% 32%,
      color-mix(in srgb, var(--axie-color-accent-soft) 62%, white) 0 22%,
      var(--axie-color-accent) 58%
    );
  box-shadow:
    0 2px 0 color-mix(in srgb, var(--axie-color-ink) 16%, transparent),
    0 10px 20px color-mix(in srgb, var(--axie-color-accent) 22%, transparent);
  transition:
    box-shadow var(--axie-motion-base) var(--axie-motion-spring),
    transform var(--axie-motion-base) var(--axie-motion-spring);
}

.axie-slider:hover::-moz-range-thumb {
  transform: scale(1.05);
}

.axie-slider:active::-moz-range-thumb {
  transform: scale(0.94);
}

.axie-slider:focus-visible::-moz-range-thumb {
  box-shadow:
    0 2px 0 color-mix(in srgb, var(--axie-color-ink) 16%, transparent),
    0 10px 20px color-mix(in srgb, var(--axie-color-accent) 22%, transparent),
    0 0 0 5px color-mix(in srgb, var(--axie-color-accent) 22%, transparent);
}

@keyframes axie-fade {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes axie-enter {
  from {
    opacity: 0;
    transform: translate3d(0, 10px, 0) scale(0.985);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-pop {
  from {
    opacity: 0;
    transform: translate3d(0, 12px, 0) scale(0.96);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-sheet-panel-in {
  from {
    opacity: 0.72;
    transform: translate3d(0, 26px, 0) scale(0.985);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-row-in {
  from {
    opacity: 0;
    transform: translate3d(0, 8px, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}

@keyframes axie-accordion-down {
  from {
    opacity: 0;
    transform: translate3d(0, -4px, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}

@keyframes axie-shimmer {
  100% {
    transform: translateX(100%);
  }
}

@keyframes axie-pulse-dot {
  0%,
  100% {
    box-shadow: 0 0 0 0 color-mix(in srgb, var(--axie-color-accent) 30%, transparent);
  }
  50% {
    box-shadow: 0 0 0 5px color-mix(in srgb, var(--axie-color-accent) 0%, transparent);
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.001ms !important;
    animation-iteration-count: 1 !important;
    scroll-behavior: auto !important;
    transition-duration: 0.001ms !important;
  }

  .axie-enter,
  .axie-pop,
  .axie-fade,
  .axie-sheet-backdrop,
  .axie-sheet-panel,
  .axie-row-enter {
    animation: none;
  }

  .axie-pressable,
  .axie-pressable:hover,
  .axie-pressable:active {
    transform: none;
  }
}
